INSERT INTO public.learning_paths (id, organization_id, name, description, is_active)
VALUES
  ('e2070000-0000-4000-8000-000000000000', NULL, '入門ロードマップ（主任になる前夜 L0.7）', 'まだ役職・権限がない前提で、段取り・対人・小さな場の仕切りを学ぶ入口。L0.7の3コースを順に。', true),
  ('e2010000-0000-4000-8000-000000000000', NULL, '初級ロードマップ（新任主任 L1）', '新任主任・リーダーが現場で最初に必要になる対人・チーム運営・数字・戦略・法務の基礎。L1の6コースを領域順に。', true),
  ('e2020000-0000-4000-8000-000000000000', NULL, '中級ロードマップ（管理者 L2）', '課長・部長級として、組織の一部として意思決定する応用レベル。L2の6コースを領域順に。', true),
  ('e2030000-0000-4000-8000-000000000000', NULL, '上級ロードマップ（経営者 L3）', '事業全体・組織全体に責任を持つ経営層向けの統合レベル。L3の6コースを領域順に。', true)
